package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import com.google.gson.JsonObject;
import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;
import java.util.Map;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a JsonElement for constructor, using JsonNull as simple element
        JsonElement element = JsonNull.INSTANCE;
        jsonTreeReader = new JsonTreeReader(element);
    }

    @Test
    public void testHasNext_withEndObject() throws Exception {
        setStackWithToken(JsonToken.END_OBJECT);
        assertFalse(jsonTreeReader.hasNext());
    }

    @Test
    public void testHasNext_withEndArray() throws Exception {
        setStackWithToken(JsonToken.END_ARRAY);
        assertFalse(jsonTreeReader.hasNext());
    }

    @Test
    public void testHasNext_withEndDocument() throws Exception {
        setStackWithToken(JsonToken.END_DOCUMENT);
        assertFalse(jsonTreeReader.hasNext());
    }

    @Test
    public void testHasNext_withOtherTokens() throws Exception {
        for (JsonToken token : JsonToken.values()) {
            if (token != JsonToken.END_OBJECT && token != JsonToken.END_ARRAY && token != JsonToken.END_DOCUMENT) {
                setStackWithToken(token);
                assertTrue(jsonTreeReader.hasNext(), "Failed for token: " + token);
            }
        }
    }

    private void setStackWithToken(JsonToken token) throws Exception {
        // Use reflection to set the stack so that peek() returns the given token
        // peek() is public and uses peekStack() private method internally, so we mock peekStack() by setting stack[stackSize-1]

        // Get stack field
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);

        // Get stackSize field
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);

        Object[] stack = (Object[]) stackField.get(jsonTreeReader);
        int stackSize = stackSizeField.getInt(jsonTreeReader);

        // We will set stackSize to 1 and set stack[0] to an object that peek() will interpret as the token.
        // Because peek() calls peekStack() which returns stack[stackSize-1], and then determines token based on that object.

        // We need to create an object so that peek() returns the desired token.
        // peek() is overridden in JsonTreeReader, so let's check the source code or behavior:
        // peek() inspects the top of the stack (stack[stackSize-1]) and returns a JsonToken accordingly.

        // We'll create minimal objects so that peek() returns the expected token:

        Object topObject;
        switch (token) {
            case BEGIN_ARRAY:
                topObject = new JsonArray();
                break;
            case END_ARRAY:
                // To get END_ARRAY, peek() expects topObject to be an Iterator whose hasNext() is false
                topObject = new Iterator<Object>() {
                    @Override
                    public boolean hasNext() { return false; }
                    @Override
                    public Object next() { return null; }
                };
                break;
            case BEGIN_OBJECT:
                topObject = new JsonObject();
                break;
            case END_OBJECT:
                // To get END_OBJECT, peek() expects topObject to be an Iterator whose hasNext() is false
                topObject = new Iterator<Object>() {
                    @Override
                    public boolean hasNext() { return false; }
                    @Override
                    public Object next() { return null; }
                };
                break;
            case NAME:
                // peek() returns NAME if topObject is an Iterator with hasNext() true and next() returns Map.Entry
                topObject = new Iterator<Map.Entry<String, JsonElement>>() {
                    boolean returned = false;
                    @Override
                    public boolean hasNext() { return !returned; }
                    @Override
                    public Map.Entry<String, JsonElement> next() {
                        returned = true;
                        return Map.entry("key", JsonNull.INSTANCE);
                    }
                };
                break;
            case STRING:
                topObject = new JsonPrimitive("string");
                break;
            case NUMBER:
                topObject = new JsonPrimitive(1);
                break;
            case BOOLEAN:
                topObject = new JsonPrimitive(true);
                break;
            case NULL:
                topObject = JsonNull.INSTANCE;
                break;
            case END_DOCUMENT:
                // stackSize == 0 means end document
                stackSizeField.setInt(jsonTreeReader, 0);
                return;
            default:
                // fallback to JsonNull
                topObject = JsonNull.INSTANCE;
                break;
        }

        stack[0] = topObject;
        stackSizeField.setInt(jsonTreeReader, 1);
    }
}
